import{_ as t,o as n,c as o,ag as a}from"./chunks/framework.BZohXCq9.js";const m=JSON.parse('{"title":"[Thiết kế Cơ bản] Module: Khám phá & Tìm kiếm (User Flow & IA)","description":"","frontmatter":{},"headers":[],"relativePath":"05-quan-ly-sprint/sprint-3-tim-kiem-kham-pha/02-thiet-ke-co-ban.md","filePath":"05-quan-ly-sprint/sprint-3-tim-kiem-kham-pha/02-thiet-ke-co-ban.md"}'),e={name:"05-quan-ly-sprint/sprint-3-tim-kiem-kham-pha/02-thiet-ke-co-ban.md"};function r(h,i,l,u,c,g){return n(),o("div",null,[...i[0]||(i[0]=[a('<h1 id="thiet-ke-co-ban-module-kham-pha-tim-kiem-user-flow-ia" tabindex="-1">[Thiết kế Cơ bản] Module: Khám phá &amp; Tìm kiếm (User Flow &amp; IA) <a class="header-anchor" href="#thiet-ke-co-ban-module-kham-pha-tim-kiem-user-flow-ia" aria-label="Permalink to &quot;[Thiết kế Cơ bản] Module: Khám phá &amp; Tìm kiếm (User Flow &amp; IA)&quot;">​</a></h1><p>Tài liệu thiết kế cơ bản cho module Discovery &amp; Search, mô tả luồng người dùng (User Stories) và kiến trúc thông tin (Information Architecture).</p><h2 id="_1-luong-nguoi-dung-user-flow" tabindex="-1">1. Luồng Người dùng (User Flow) <a class="header-anchor" href="#_1-luong-nguoi-dung-user-flow" aria-label="Permalink to &quot;1. Luồng Người dùng (User Flow)&quot;">​</a></h2><h3 id="story-1-tim-kiem-theo-vung-mien-tour-noi-bat" tabindex="-1">Story 1: Tìm kiếm theo Vùng miền &amp; Tour nổi bật <a class="header-anchor" href="#story-1-tim-kiem-theo-vung-mien-tour-noi-bat" aria-label="Permalink to &quot;Story 1: Tìm kiếm theo Vùng miền &amp; Tour nổi bật&quot;">​</a></h3><ul><li><strong>Actor</strong>: Khách hàng vãng lai.</li><li><strong>Quy trình</strong>: <ol><li>Truy cập <strong>Homepage</strong>.</li><li>Một danh sách &quot;Điểm đến tiêu biểu&quot; (với ảnh Cloudinary lung linh) xuất hiện.</li><li>Click vào card <strong>Vịnh Hạ Long</strong>.</li><li>Chuyển sang màn hình <strong>Discovery</strong>. Hiển thị bản đồ vị trí Quảng Ninh và danh sách tour xuất phát tại đây.</li></ol></li></ul><h3 id="story-2-loc-tour-theo-khoang-gia-loai-hinh" tabindex="-1">Story 2: Lọc Tour theo Khoảng giá &amp; Loại hình <a class="header-anchor" href="#story-2-loc-tour-theo-khoang-gia-loai-hinh" aria-label="Permalink to &quot;Story 2: Lọc Tour theo Khoảng giá &amp; Loại hình&quot;">​</a></h3><ul><li><strong>Actor</strong>: Khách hàng có nhu cầu cụ thể.</li><li><strong>Quy trình</strong>: <ol><li>Nhập từ khóa &quot;Nghỉ dưỡng&quot; tại ô <strong>Search</strong>.</li><li>Nhấn nút &quot;Lọc&quot; (Filter).</li><li>Điều chỉnh thanh Slider cho khoảng giá từ 0 - 5.000.000 VNĐ.</li><li>Chọn loại hình &quot;Biển đảo&quot;.</li><li>Nhấn &quot;Áp dụng&quot;. Kết quả lọc ngay lập tức thay đổi.</li></ol></li></ul><h2 id="_2-kien-truc-thong-tin-information-architecture" tabindex="-1">2. Kiến trúc Thông tin (Information Architecture) <a class="header-anchor" href="#_2-kien-truc-thong-tin-information-architecture" aria-label="Permalink to &quot;2. Kiến trúc Thông tin (Information Architecture)&quot;">​</a></h2><h3 id="man-hinh-ket-qua-tim-kiem-search-result-page" tabindex="-1">Màn hình Kết quả Tìm kiếm (Search Result Page) <a class="header-anchor" href="#man-hinh-ket-qua-tim-kiem-search-result-page" aria-label="Permalink to &quot;Màn hình Kết quả Tìm kiếm (Search Result Page)&quot;">​</a></h3><ul><li><strong>Header</strong>: Thanh search thu gọn (Sticky).</li><li><strong>Sidebar (Left)</strong>: Bộ lọc lọc theo Region, Price, Rate, Categories.</li><li><strong>Main Area (Center)</strong>: Grid view các Card Tour &amp; Destination.</li><li><strong>View Switcher</strong>: Chuyển đổi giữa View dạng Danh sách, Grid hoặc Bản đồ (Map).</li></ul><h2 id="_3-đac-ta-đieu-huong-navigation-logic" tabindex="-1">3. Đặc tả Điều hướng (Navigation Logic) <a class="header-anchor" href="#_3-đac-ta-đieu-huong-navigation-logic" aria-label="Permalink to &quot;3. Đặc tả Điều hướng (Navigation Logic)&quot;">​</a></h2><ul><li><strong>Back behavior</strong>: Nút quay lại giữ nguyên các lựa chọn filter trước đó.</li><li><strong>Deeplink</strong>: Mỗi bộ lọc được phản ánh lên URL (e.g. <code>?region=north&amp;price_max=5000000</code>). Giúp người dùng dễ dàng chia sẻ kết quả tìm kiếm qua mạng xã hội.</li></ul><hr><p><em>Bản thiết kế sơ bộ bởi PO/BA cho Sprint 3.</em></p>',14)])])}const d=t(e,[["render",r]]);export{m as __pageData,d as default};
